const results = [];
const seenInRun = new Set();

// Seller/for-hire signals — skip these posts
const sellerSignals = [
  'i will ', 'i am a ', 'i offer', 'i provide', 'my services',
  'for hire', 'available for hire', 'freelancer available',
  'portfolio:', 'years of experience', 'i specialize in',
  'my rates', 'i can help you', 'hire me', 'i am available',
  'my approach', 'check out my', 'visit my', 'contact me for',
  'competitive rates', 'reach out to me', 'i have been working',
  'i am offering', 'seeking clients', 'seeking employment',
  'looking for work', 'seeking work', 'looking for clients',
  'experienced developer', 'senior developer available',
  'i will design', 'i will build', 'i will develop'
];

// Buyer/project signals — at least one must be present
const buyerSignals = [
  'looking for', 'need', 'seeking', 'wanted', 'want to hire',
  'build', 'develop', 'create', 'project', 'contract work',
  'budget', 'hire', 'hiring', 'require', 'must have',
  'will pay', 'compensation', 'work needed', 'job', 'task',
  'help with', 'assist', 'build me', 'we need', 'our company',
  'our startup', 'our business', 'small business'
];

for (const item of $input.all()) {
  const data = item.json;

  const title = String(data.title || '').trim().substring(0, 500);
  const link  = String(data.link || data.guid || '').trim();
  const rawContent = data.content || data.contentSnippet || data.description || '';
  const description = String(rawContent).replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim().substring(0, 3000);
  const pubDate = data.isoDate || data.pubDate || '';
  const guid    = String(data.guid || link);

  if (!title || !link) continue;

  const id = 'craigslist_' + guid.replace(/[^a-z0-9]/gi, '').slice(-60);
  if (seenInRun.has(id)) continue;
  seenInRun.add(id);

  const fullText = (title + ' ' + description).toLowerCase();

  // Skip seller posts
  if (sellerSignals.some(kw => fullText.includes(kw))) continue;

  // Must have at least one buyer signal
  if (!buyerSignals.some(kw => fullText.includes(kw))) continue;

  // Detect city from URL domain
  let city = 'USA';
  if (link.includes('newyork.craigslist'))      city = 'New York, NY';
  else if (link.includes('sfbay.craigslist'))    city = 'San Francisco, CA';
  else if (link.includes('losangeles.craigslist')) city = 'Los Angeles, CA';
  else if (link.includes('chicago.craigslist'))  city = 'Chicago, IL';
  else if (link.includes('austin.craigslist'))   city = 'Austin, TX';

  // Extract any budget mention
  let budget_text = '';
  const budgetMatch = (title + ' ' + description).match(/\$[\d,]+(?:k)?(?:\s*[-–]\s*\$?[\d,]+(?:k)?)?/i);
  if (budgetMatch) budget_text = budgetMatch[0].trim().substring(0, 80);

  let posted_at = new Date().toISOString();
  try { if (pubDate) posted_at = new Date(pubDate).toISOString(); } catch(e) {}

  results.push({ json: {
    title,
    description,
    source: 'craigslist',
    source_url: link,
    source_id: id,
    posted_at,
    author: '',
    subreddit: 'craigslist_computer_gigs',
    upvotes: 0,
    num_comments: 0,
    flair_text: 'Computer Gigs',
    budget_text,
    platform: 'craigslist',
    location: city
  }});
}

if (results.length === 0) return [{ json: { _empty: true, platform: 'craigslist' } }];
// Cap at 30 leads per run
return results.slice(0, 30);

const post = $input.item.json;
if (post._empty) return { json: post };

const apiKey = $env.GOOGLE_AI_API_KEY;

const SYSTEM_PROMPT = `You are a senior business development analyst for ScaleBuild AI (CEO: Ujjwal Roy, ex-Intel/IBM/Micron), a custom AI/ML software development company.

ScaleBuild BUILDS: AI/ML models, computer vision, enterprise automation, custom software, full-stack web/mobile apps, data pipelines, API integrations.

These leads are from Craigslist Computer Gigs sections in major US metros (NYC, SF Bay Area, LA, Chicago, Austin). These are REAL project postings from local businesses, startups, and entrepreneurs actively seeking technical help. Craigslist Computer Gigs represent NEAR-ZERO COMPETITION opportunities because agencies ignore Craigslist — making even $5K-$20K projects highly valuable to pursue.

IDEAL LEAD: A business or individual posting a genuine project request for custom software, AI/ML, automation, web/mobile app, data analysis, API work, or any technical project.

HARD EXCLUSIONS — Score overall_score 0.0 immediately, do not process:
- Lead is from India or an Indian company (location: India, .in domain, Indian city/company name context) → 0.0
- Lead is requesting to build a SaaS subscription product (we do NOT build SaaS products) → 0.0  
- Budget is clearly under $10,000 OR budget_score would be below 0.3 → 0.0
- Individual freelancer or [For Hire] ad → 0.0

SCORE 4 DIMENSIONS (0.0-1.0):
1. relevance_score: 1.0=explicit AI/ML/automation/computer vision project | 0.8=custom software or enterprise app | 0.6=web/mobile app, SaaS, or API project | 0.4=general tech work (data entry tools, basic websites) | 0.2=completely unrelated
2. budget_score: 1.0=$50K+ | 0.8=$25-50K | 0.6=$10-25K | 0.5=unknown but clearly a real project | 0.4=$5-10K | 0.2=<$5K or very vague/unclear
3. urgency_score: 1.0=ASAP/urgent/immediately | 0.8=deadline within 2 weeks | 0.6=within a month | 0.4=flexible timing mentioned | 0.2=no urgency signals
4. win_probability: 0.9+=local business posting with perfect AI/ML or automation fit | 0.8=clear project with stated budget, great fit | 0.7=good fit with some scope ambiguity | 0.5=competitive or vague scope | 0.3=very small budget or unclear intent | 0.1=no fit

BUDGET ESTIMATION (ALWAYS fill estimated_budget_text, never null):
- AI/ML project → "$10K-$50K (AI/ML Craigslist scope)"
- Automation/workflow → "$5K-$30K (automation scope)"
- Full-stack web/mobile app → "$5K-$25K (Craigslist app scope)"
- SaaS or complex platform → "$15K-$75K (platform scope)"
- Data/analytics work → "$3K-$20K (data project scope)"
- Unknown → "$5K-$25K (estimated Craigslist project)"

COMPANY EXTRACTION: Extract company name, contact name, website from title/snippet/URL. Never invent. Return null if not found.`;

const prompt = SYSTEM_PROMPT + `\n\nScore this Craigslist Computer Gigs lead. Return ONLY a single valid JSON object:\n{"relevance_score":0.0,"budget_score":0.0,"urgency_score":0.0,"win_probability":0.0,"client_context":"Detailed description of who the client is (company, industry, current situation)","project_context":"Detailed description of what they want built (specific technical requirements, goals)","summary":"3-5 sentence summary: what the poster needs, the project scope, any budget or deadline signals, and why ScaleBuild AI is the right fit. Note the city.","industry":"FinTech/HealthTech/SaaS/eCommerce/Local Business/Startup/Manufacturing/Logistics/General","tags":["tag1","tag2"],"reasoning":"Full detailed AI reasoning: explain each score dimension — why this relevance, why this budget estimate, why this urgency, why this win probability. Mention the near-zero competition advantage and recommended outreach approach.","estimated_budget_text":"$X-$Y (reason)","deadline_text":null,"tech_stack":[],"company_name":null,"lead_founder_name":null,"lead_website":null}\n\nTitle: ${post.title}\nCity: ${post.location||'USA'}\nDescription: ${(post.description||'').substring(0, 1200)}${post.budget_text ? '\nBudget Mentioned: ' + post.budget_text : ''}`;

const body = {
  contents: [{ parts: [{ text: prompt }] }],
  generationConfig: { maxOutputTokens: 100000, temperature: 0.2, responseMimeType: 'application/json' }
};

let s = null;
try {
  const respRaw = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=' + apiKey,
    body
  });
  const resp = typeof respRaw === 'string' ? JSON.parse(respRaw) : respRaw;
  const raw = resp?.candidates?.[0]?.content?.parts?.[0]?.text || '';
  const cleaned = raw.replace(/```json[\s\S]*?```|```/g, '').trim();
  const match = cleaned.match(/\{[\s\S]*\}/);
  if (match) s = JSON.parse(match[0]);
} catch(e) {}

if (!s) s = {
  relevance_score: 0.4, budget_score: 0.4, urgency_score: 0.3, win_probability: 0.5,
  client_context: 'Could not extract client context',
  project_context: 'Could not extract project context',
  summary: 'Parse error — using defaults', industry: 'General', tags: [], reasoning: 'Could not parse Gemini response',
  estimated_budget_text: '$5K-$25K (estimated Craigslist project)',
  deadline_text: null, tech_stack: [], company_name: null, lead_founder_name: null, lead_website: null
};

const overall = Math.round(((s.relevance_score*0.35)+(s.budget_score*0.30)+(s.urgency_score*0.15)+(s.win_probability*0.20))*100)/100;
const alert_tier = overall>=0.85?'instant':overall>=0.70?'digest':overall>=0.30?'dashboard':'discard';

return { json: {
  source_id: post.source_id, title: post.title, description: post.description,
  source: post.source, source_url: post.source_url, posted_at: post.posted_at,
  author: post.author||'', subreddit: post.subreddit||'craigslist_computer_gigs',
  upvotes: 0, num_comments: 0, flair_text: 'Computer Gigs',
  relevance_score: s.relevance_score, budget_score: s.budget_score,
  urgency_score: s.urgency_score, win_probability: s.win_probability,
  overall_score: overall, 
  ai_summary: s.summary, 
  client_context: s.client_context,
  project_context: s.project_context,
  industry: s.industry,
  ai_tags: s.tags||[], ai_reasoning: s.reasoning,
  estimated_budget_text: s.estimated_budget_text||'',
  budget_mentioned: post.budget_text || s.estimated_budget_text || '',
  tech_stack: s.tech_stack||[], company_name: s.company_name||null,
  lead_founder: s.lead_founder_name||null, lead_company: s.company_name||null,
  lead_website: s.lead_website||null, lead_contact: null,
  lead_score: Math.round(overall*10),
  alert_tier, discovered_at: new Date().toISOString(), status: 'new',
  location: post.location||null, deadline_text: s.deadline_text||null,
  outreach_draft: '',
  hunter_name:'', hunter_email:'', hunter_title:'', hunter_company:'',
  hunter_all_emails:'', hunter_all_names:'', hunter_all_titles:''
}};

const hunterResp = $input.item.json;
const original = $('Check - Has Lead Info').item.json;
const data = hunterResp?.data || {};
const emails = data.emails || [];
const org = data.organization || original.lead_company || '';

if (emails.length === 0) {
  return [{ json: { ...original, hunter_name: '', hunter_email: '', hunter_title: '', hunter_company: org, hunter_all_emails: '', hunter_all_names: '', hunter_all_titles: '' } }];
}

const priority = ['ceo','founder','co-founder','cto','owner','president','vp','director'];
const best = emails.find(e => priority.some(t => (e.position||'').toLowerCase().includes(t))) || emails[0];

const allEmails  = emails.map(e => e.value || '').filter(Boolean).join(', ');
const allNames   = emails.map(e => (e.first_name||e.last_name) ? `${e.first_name||''} ${e.last_name||''}`.trim() : '').filter(Boolean).join(', ');
const allTitles  = emails.map(e => e.position || '').filter(Boolean).join(', ');

return [{ json: {
  ...original,
  hunter_name:       best.first_name || best.last_name ? `${best.first_name||''} ${best.last_name||''}`.trim() : '',
  hunter_email:      best.value || '',
  hunter_title:      best.position || '',
  hunter_company:    org,
  hunter_all_emails: allEmails,
  hunter_all_names:  allNames,
  hunter_all_titles: allTitles
}}];

const seen = new Map();
for (const item of $input.all()) {
  const id = item.json.source_id;
  if (!id) continue;
  if (!seen.has(id)) {
    seen.set(id, item.json);
  } else {
    if (item.json.hunter_email && !seen.get(id).hunter_email) {
      seen.set(id, item.json);
    }
  }
}
return [...seen.values()]
  .sort((a, b) => (b.overall_score||0) - (a.overall_score||0))
  .map(json => ({ json }));
